  1â†’//go:build e2e
  2â†’
  3â†’package e2e
  4â†’
  5â†’import (
  6â†’	"encoding/json"
  7â†’	"fmt"
  8â†’	"os"
  9â†’	"os/exec"
 10â†’	"path/filepath"
 11â†’	"testing"
 12â†’)
 13â†’
 14â†’// TestEnv provides an isolated filesystem environment for E2E tests.
 15â†’type TestEnv struct {
 16â†’	t       *testing.T
 17â†’	Dir     string
 18â†’	HomeDir string
 19â†’	Runner  *AgentRunner
 20â†’}
 21â†’
 22â†’// NewTestEnv creates a bare test environment with ENTIRE_REPO_ROOT and isolated HOME.
 23â†’func NewTestEnv(t *testing.T, agentName string) *TestEnv {
 24â†’	t.Helper()
 25â†’
 26â†’	binPath, ok := agentBinaries[agentName]
 27â†’	if !ok {
 28â†’		t.Fatalf("agent binary not found: %s (available: %v)", agentName, agentBinaryNames())
 29â†’	}
 30â†’
 31â†’	dir := t.TempDir()
 32â†’	homeDir := t.TempDir()
 33â†’
 34â†’	env := baseEnv(dir, homeDir)
 35â†’
 36â†’	return &TestEnv{
 37â†’		t:       t,
 38â†’		Dir:     dir,
 39â†’		HomeDir: homeDir,
 40â†’		Runner: &AgentRunner{
 41â†’			BinaryPath: binPath,
 42â†’			Env:        env,
 43â†’		},
 44â†’	}
 45â†’}
 46â†’
 47â†’// NewKiroTestEnv creates a test environment with .kiro/ and .entire/tmp/ directories.
 48â†’func NewKiroTestEnv(t *testing.T) *TestEnv {
 49â†’	t.Helper()
 50â†’	te := NewTestEnv(t, "entire-agent-kiro")
 51â†’	te.MkdirAll(".kiro")
 52â†’	te.MkdirAll(".entire/tmp")
 53â†’	return te
 54â†’}
 55â†’
 56â†’// NewKiroGitEnv creates a Kiro test environment with git init.
 57â†’func NewKiroGitEnv(t *testing.T) *TestEnv {
 58â†’	t.Helper()
 59â†’	te := NewKiroTestEnv(t)
 60â†’	te.GitInit()
 61â†’	return te
 62â†’}
 63â†’
 64â†’// WriteFile writes content to a path relative to the test environment root.
 65â†’func (e *TestEnv) WriteFile(relPath, content string) {
 66â†’	e.t.Helper()
 67â†’	abs := filepath.Join(e.Dir, relPath)
 68â†’	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
 69â†’		e.t.Fatalf("mkdir for %s: %v", relPath, err)
 70â†’	}
 71â†’	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
 72â†’		e.t.Fatalf("write %s: %v", relPath, err)
 73â†’	}
 74â†’}
 75â†’
 76â†’// WriteJSON writes a JSON-encoded value to a path relative to the test root.
 77â†’func (e *TestEnv) WriteJSON(relPath string, v any) {
 78â†’	e.t.Helper()
 79â†’	data, err := json.Marshal(v)
 80â†’	if err != nil {
 81â†’		e.t.Fatalf("marshal JSON for %s: %v", relPath, err)
 82â†’	}
 83â†’	e.WriteFile(relPath, string(data))
 84â†’}
 85â†’
 86â†’// ReadFile reads a file relative to the test environment root.
 87â†’func (e *TestEnv) ReadFile(relPath string) string {
 88â†’	e.t.Helper()
 89â†’	data, err := os.ReadFile(filepath.Join(e.Dir, relPath))
 90â†’	if err != nil {
 91â†’		e.t.Fatalf("read %s: %v", relPath, err)
 92â†’	}
 93â†’	return string(data)
 94â†’}
 95â†’
 96â†’// FileExists checks whether a relative path exists in the test environment.
 97â†’func (e *TestEnv) FileExists(relPath string) bool {
 98â†’	_, err := os.Stat(filepath.Join(e.Dir, relPath))
 99â†’	return err == nil
100â†’}
101â†’
102â†’// MkdirAll creates a directory (and parents) relative to the test root.
103â†’func (e *TestEnv) MkdirAll(relPath string) {
104â†’	e.t.Helper()
105â†’	if err := os.MkdirAll(filepath.Join(e.Dir, relPath), 0o750); err != nil {
106â†’		e.t.Fatalf("mkdir %s: %v", relPath, err)
107â†’	}
108â†’}
109â†’
110â†’// GitInit initializes a git repo in the test environment root.
111â†’func (e *TestEnv) GitInit() {
112â†’	e.t.Helper()
113â†’	cmd := exec.Command("git", "init")
114â†’	cmd.Dir = e.Dir
115â†’	cmd.Env = e.Runner.Env
116â†’	if out, err := cmd.CombinedOutput(); err != nil {
117â†’		e.t.Fatalf("git init failed: %v\n%s", err, out)
118â†’	}
119â†’}
120â†’
121â†’// AbsPath returns the absolute path for a relative path in the test environment.
122â†’func (e *TestEnv) AbsPath(relPath string) string {
123â†’	return filepath.Join(e.Dir, relPath)
124â†’}
125â†’
126â†’func baseEnv(repoRoot, homeDir string) []string {
127â†’	return []string{
128â†’		fmt.Sprintf("ENTIRE_REPO_ROOT=%s", repoRoot),
129â†’		fmt.Sprintf("HOME=%s", homeDir),
130â†’		fmt.Sprintf("PATH=%s", os.Getenv("PATH")),
131â†’		"LANG=en_US.UTF-8",
132â†’	}
133â†’}
134â†’
135â†’func agentBinaryNames() []string {
136â†’	names := make([]string, 0, len(agentBinaries))
137â†’	for name := range agentBinaries {
138â†’		names = append(names, name)
139â†’	}
140â†’	return names
141â†’}
