  1â†’//go:build e2e
  2â†’
  3â†’package e2e
  4â†’
  5â†’import (
  6â†’	"fmt"
  7â†’	"os"
  8â†’	"os/exec"
  9â†’	"path/filepath"
 10â†’	"strings"
 11â†’	"testing"
 12â†’)
 13â†’
 14â†’// agentBinaries maps agent names to their built binary paths.
 15â†’var agentBinaries = map[string]string{}
 16â†’
 17â†’func TestMain(m *testing.M) {
 18â†’	tmpDir, err := os.MkdirTemp("", "e2e-agents-*")
 19â†’	if err != nil {
 20â†’		fmt.Fprintf(os.Stderr, "failed to create temp dir: %v\n", err)
 21â†’		os.Exit(1)
 22â†’	}
 23â†’	defer os.RemoveAll(tmpDir)
 24â†’
 25â†’	agents, err := discoverAgents()
 26â†’	if err != nil {
 27â†’		fmt.Fprintf(os.Stderr, "failed to discover agents: %v\n", err)
 28â†’		os.Exit(1)
 29â†’	}
 30â†’
 31â†’	if len(agents) == 0 {
 32â†’		fmt.Fprintln(os.Stderr, "no agents found in agents/ directory")
 33â†’		os.Exit(1)
 34â†’	}
 35â†’
 36â†’	for _, agentDir := range agents {
 37â†’		agentName := filepath.Base(agentDir)
 38â†’		binPath := filepath.Join(tmpDir, agentName)
 39â†’		// Each agent has its own go.mod, so build from the agent's directory
 40â†’		agentAbsDir := filepath.Join(repoRoot(), agentDir)
 41â†’		mainPkg := "./cmd/" + agentName
 42â†’
 43â†’		fmt.Printf("Building %s...\n", agentName)
 44â†’		cmd := exec.Command("go", "build", "-o", binPath, mainPkg)
 45â†’		cmd.Dir = agentAbsDir
 46â†’		cmd.Stdout = os.Stdout
 47â†’		cmd.Stderr = os.Stderr
 48â†’		if err := cmd.Run(); err != nil {
 49â†’			fmt.Fprintf(os.Stderr, "failed to build %s: %v\n", agentName, err)
 50â†’			os.Exit(1)
 51â†’		}
 52â†’
 53â†’		agentBinaries[agentName] = binPath
 54â†’		fmt.Printf("Built %s -> %s\n", agentName, binPath)
 55â†’	}
 56â†’
 57â†’	// Add the temp bin directory to PATH so that `entire enable` can discover
 58â†’	// the agent binaries (e.g. entire-agent-kiro) during lifecycle tests.
 59â†’	os.Setenv("PATH", tmpDir+string(os.PathListSeparator)+os.Getenv("PATH"))
 60â†’
 61â†’	os.Exit(m.Run())
 62â†’}
 63â†’
 64â†’func discoverAgents() ([]string, error) {
 65â†’	agentsDir := filepath.Join(repoRoot(), "agents")
 66â†’	entries, err := os.ReadDir(agentsDir)
 67â†’	if err != nil {
 68â†’		return nil, fmt.Errorf("read agents dir: %w", err)
 69â†’	}
 70â†’
 71â†’	var agents []string
 72â†’	for _, entry := range entries {
 73â†’		if !entry.IsDir() {
 74â†’			continue
 75â†’		}
 76â†’		if !strings.HasPrefix(entry.Name(), "entire-agent-") {
 77â†’			continue
 78â†’		}
 79â†’		// Verify it has a cmd/<name>/main.go
 80â†’		mainFile := filepath.Join(agentsDir, entry.Name(), "cmd", entry.Name(), "main.go")
 81â†’		if _, err := os.Stat(mainFile); err != nil {
 82â†’			continue
 83â†’		}
 84â†’		agents = append(agents, filepath.Join("agents", entry.Name()))
 85â†’	}
 86â†’	return agents, nil
 87â†’}
 88â†’
 89â†’func repoRoot() string {
 90â†’	// Walk up from e2e/ to find the repo root
 91â†’	dir, err := os.Getwd()
 92â†’	if err != nil {
 93â†’		return ".."
 94â†’	}
 95â†’	// If we're in the e2e directory, go up one level
 96â†’	if filepath.Base(dir) == "e2e" {
 97â†’		return filepath.Dir(dir)
 98â†’	}
 99â†’	return dir
100â†’}
