 1â†’//go:build e2e
 2â†’
 3â†’package e2e
 4â†’
 5â†’import (
 6â†’	"bytes"
 7â†’	"encoding/json"
 8â†’	"errors"
 9â†’	"os/exec"
10â†’	"testing"
11â†’)
12â†’
13â†’// CommandResult holds the output of a binary invocation.
14â†’type CommandResult struct {
15â†’	Stdout   []byte
16â†’	Stderr   []byte
17â†’	ExitCode int
18â†’	Err      error
19â†’}
20â†’
21â†’// AgentRunner invokes an agent binary with subcommands.
22â†’type AgentRunner struct {
23â†’	BinaryPath string
24â†’	Env        []string
25â†’}
26â†’
27â†’// Run executes the agent binary with the given subcommand, args, and optional stdin.
28â†’func (r *AgentRunner) Run(stdin string, subcommand string, args ...string) CommandResult {
29â†’	cmdArgs := append([]string{subcommand}, args...)
30â†’	cmd := exec.Command(r.BinaryPath, cmdArgs...)
31â†’	cmd.Stdin = bytes.NewBufferString(stdin)
32â†’	cmd.Env = r.Env
33â†’
34â†’	var stdout, stderr bytes.Buffer
35â†’	cmd.Stdout = &stdout
36â†’	cmd.Stderr = &stderr
37â†’
38â†’	err := cmd.Run()
39â†’	exitCode := 0
40â†’	if err != nil {
41â†’		var exitErr *exec.ExitError
42â†’		if errors.As(err, &exitErr) {
43â†’			exitCode = exitErr.ExitCode()
44â†’		} else {
45â†’			exitCode = -1
46â†’		}
47â†’	}
48â†’
49â†’	return CommandResult{
50â†’		Stdout:   stdout.Bytes(),
51â†’		Stderr:   stderr.Bytes(),
52â†’		ExitCode: exitCode,
53â†’		Err:      err,
54â†’	}
55â†’}
56â†’
57â†’// RunJSON executes the subcommand and JSON-decodes stdout into dest.
58â†’func (r *AgentRunner) RunJSON(t *testing.T, dest any, stdin string, subcommand string, args ...string) CommandResult {
59â†’	t.Helper()
60â†’	result := r.Run(stdin, subcommand, args...)
61â†’	if result.ExitCode != 0 {
62â†’		t.Fatalf("%s %s failed (exit %d): %s", r.BinaryPath, subcommand, result.ExitCode, result.Stderr)
63â†’	}
64â†’	if err := json.Unmarshal(result.Stdout, dest); err != nil {
65â†’		t.Fatalf("failed to decode JSON from %s %s: %v\nstdout: %s", r.BinaryPath, subcommand, err, result.Stdout)
66â†’	}
67â†’	return result
68â†’}
69â†’
70â†’// MustSucceed asserts the subcommand exits with code 0.
71â†’func (r *AgentRunner) MustSucceed(t *testing.T, stdin string, subcommand string, args ...string) CommandResult {
72â†’	t.Helper()
73â†’	result := r.Run(stdin, subcommand, args...)
74â†’	if result.ExitCode != 0 {
75â†’		t.Fatalf("%s %s: expected exit 0, got %d\nstderr: %s", r.BinaryPath, subcommand, result.ExitCode, result.Stderr)
76â†’	}
77â†’	return result
78â†’}
79â†’
80â†’// MustFail asserts the subcommand exits with a non-zero code.
81â†’func (r *AgentRunner) MustFail(t *testing.T, stdin string, subcommand string, args ...string) CommandResult {
82â†’	t.Helper()
83â†’	result := r.Run(stdin, subcommand, args...)
84â†’	if result.ExitCode == 0 {
85â†’		t.Fatalf("%s %s: expected non-zero exit, got 0\nstdout: %s", r.BinaryPath, subcommand, result.Stdout)
86â†’	}
87â†’	return result
88â†’}
