 10â†’	"strings"
 11â†’	"testing"
 12â†’	"time"
 13â†’)
 14â†’
 15â†’// LifecycleEnv provides a full-lifecycle test environment: a git repo with
 16â†’// `entire enable` already run, ready for agent prompts and checkpoint assertions.
 17â†’type LifecycleEnv struct {
 18â†’	Dir     string   // repo root (temp dir)
 19â†’	HomeDir string   // isolated HOME
 20â†’	Env     []string // environment variables for subprocesses
 21â†’	Agent   string   // agent name (e.g. "kiro")
 22â†’}
 23â†’
 24â†’// NewLifecycleEnv creates a temp git repo, writes an initial commit, and runs
 25â†’// `entire enable --agent <agentName>`. It also writes .entire/settings.json
 26â†’// with external_agents enabled.
 27â†’func NewLifecycleEnv(t *testing.T, agentName string) *LifecycleEnv {
 28â†’	t.Helper()
 29â†’
 30â†’	dir := t.TempDir()
 31â†’	homeDir := t.TempDir()
 32â†’
 33â†’	env := lifecycleEnv(dir, homeDir)
 34â†’
 35â†’	le := &LifecycleEnv{
 36â†’		Dir:     dir,
 37â†’		HomeDir: homeDir,
 38â†’		Env:     env,
 39â†’		Agent:   agentName,
 40â†’	}
 41â†’
 42â†’	// Initialize git repo with a seed commit.
 43â†’	le.Git(t, "init")
 44â†’	le.Git(t, "config", "user.email", "test@test.com")
 45â†’	le.Git(t, "config", "user.name", "Test User")
 46â†’	le.WriteFile(t, "README.md", "# test repo\n")
 47â†’	le.Git(t, "add", ".")
 48â†’	le.Git(t, "commit", "-m", "initial commit")
 49â†’
 50â†’	// Write .entire/settings.json with external_agents enabled.
 51â†’	le.MkdirAll(t, ".entire")
 52â†’	le.WriteFile(t, ".entire/settings.json", `{"external_agents":true}`)
 53â†’
 54â†’	// Run entire enable.
 55â†’	EntireEnable(t, dir, agentName, env)
 56â†’
 57â†’	return le
 58â†’}
 59â†’
 60â†’// Git runs a git command in the repo dir; fails the test on error.
 61â†’func (le *LifecycleEnv) Git(t *testing.T, args ...string) {
 62â†’	t.Helper()
 63â†’	cmd := exec.Command("git", args...)
 64â†’	cmd.Dir = le.Dir
 65â†’	cmd.Env = le.Env
 66â†’	if out, err := cmd.CombinedOutput(); err != nil {
 67â†’		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 68â†’	}
 69â†’}
 70â†’
 71â†’// GitOutput runs a git command and returns its combined output.
 72â†’func (le *LifecycleEnv) GitOutput(t *testing.T, args ...string) string {
 73â†’	t.Helper()
 74â†’	cmd := exec.Command("git", args...)
 75â†’	cmd.Dir = le.Dir
 76â†’	cmd.Env = le.Env
 77â†’	out, err := cmd.CombinedOutput()
 78â†’	if err != nil {
 79â†’		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 80â†’	}
 81â†’	return string(out)
 82â†’}
 83â†’
 84â†’// RunKiroPrompt runs `kiro-cli-chat chat --no-interactive --trust-all-tools --agent entire <prompt>`.
 85â†’func (le *LifecycleEnv) RunKiroPrompt(t *testing.T, prompt string) error {
 86â†’	t.Helper()
 87â†’	bin, err := exec.LookPath("kiro-cli-chat")
 88â†’	if err != nil {
 89â†’		t.Fatalf("kiro-cli-chat not in PATH: %v", err)
 90â†’	}
 91â†’	cmd := exec.Command(bin, "chat", "--no-interactive", "--trust-all-tools", "--agent", "entire", prompt)
 92â†’	cmd.Dir = le.Dir
 93â†’	cmd.Env = le.Env
 94â†’	out, err := cmd.CombinedOutput()
 95â†’	if err != nil {
 96â†’		t.Logf("kiro-cli-chat output:\n%s", out)
 97â†’		return fmt.Errorf("kiro-cli-chat: %w", err)
 98â†’	}
 99â†’	t.Logf("kiro-cli-chat output:\n%s", out)
100â†’	return nil
101â†’}
102â†’
103â†’// FileExists checks whether relPath exists in the repo dir.
104â†’func (le *LifecycleEnv) FileExists(relPath string) bool {
105â†’	_, err := os.Stat(filepath.Join(le.Dir, relPath))
106â†’	return err == nil
107â†’}
108â†’
109â†’// WriteFile writes content to relPath inside the repo dir.
110â†’func (le *LifecycleEnv) WriteFile(t *testing.T, relPath, content string) {
111â†’	t.Helper()
112â†’	abs := filepath.Join(le.Dir, relPath)
113â†’	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
114â†’		t.Fatalf("mkdir for %s: %v", relPath, err)
115â†’	}
116â†’	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
117â†’		t.Fatalf("write %s: %v", relPath, err)
118â†’	}
119â†’}
120â†’
121â†’// ReadFile reads a file from relPath inside the repo dir.
122â†’func (le *LifecycleEnv) ReadFile(t *testing.T, relPath string) string {
123â†’	t.Helper()
124â†’	data, err := os.ReadFile(filepath.Join(le.Dir, relPath))
125â†’	if err != nil {
126â†’		t.Fatalf("read %s: %v", relPath, err)
127â†’	}
128â†’	return string(data)
129â†’}
130â†’
131â†’// MkdirAll creates a directory (and parents) relative to the repo root.
132â†’func (le *LifecycleEnv) MkdirAll(t *testing.T, relPath string) {
133â†’	t.Helper()
134â†’	if err := os.MkdirAll(filepath.Join(le.Dir, relPath), 0o750); err != nil {
135â†’		t.Fatalf("mkdir %s: %v", relPath, err)
136â†’	}
137â†’}
138â†’
139â†’// AbsPath returns the absolute path for a relative path in the repo.
140â†’func (le *LifecycleEnv) AbsPath(relPath string) string {
141â†’	return filepath.Join(le.Dir, relPath)
142â†’}
143â†’
144â†’// WaitForCheckpoint polls for a checkpoint on the entire/checkpoints/v1 branch.
145â†’// It checks for new commits on that branch within the given timeout.
146â†’func WaitForCheckpoint(t *testing.T, le *LifecycleEnv, timeout time.Duration) {
147â†’	t.Helper()
148â†’	deadline := time.Now().Add(timeout)
149â†’	for time.Now().Before(deadline) {
150â†’		cmd := exec.Command("git", "rev-parse", "--verify", "entire/checkpoints/v1")
151â†’		cmd.Dir = le.Dir
152â†’		cmd.Env = le.Env
153â†’		if err := cmd.Run(); err == nil {
154â†’			t.Log("checkpoint branch found")
155â†’			return
156â†’		}
157â†’		time.Sleep(500 * time.Millisecond)
158â†’	}
159â†’	t.Fatal("timed out waiting for checkpoint branch entire/checkpoints/v1")
160â†’}
161â†’
162â†’// GetCheckpointTrailer extracts the Entire-Checkpoint trailer from a commit ref.
163â†’func GetCheckpointTrailer(t *testing.T, le *LifecycleEnv, ref string) string {
164â†’	t.Helper()
165â†’	out := le.GitOutput(t, "log", "-1", "--format=%B", ref)
166â†’	for _, line := range strings.Split(out, "\n") {
167â†’		if strings.HasPrefix(line, "Entire-Checkpoint:") {
168â†’			return strings.TrimSpace(strings.TrimPrefix(line, "Entire-Checkpoint:"))
169â†’		}
170â†’	}
171â†’	return ""
172â†’}
173â†’
174â†’// AssertFileExists fails the test if no file matches relPath in the repo.
175â†’func AssertFileExists(t *testing.T, le *LifecycleEnv, relPath string) {
176â†’	t.Helper()
177â†’	if !le.FileExists(relPath) {
178â†’		t.Errorf("expected file %s to exist", relPath)
179â†’	}
180â†’}
181â†’
182â†’// requireEntire fails or skips the test if the entire binary is not available.
183â†’// When E2E_REQUIRE_LIFECYCLE=1 (set by `make test-e2e-lifecycle`), it fails
184â†’// instead of skipping so you know immediately that your environment is missing deps.
185â†’func requireEntire(t *testing.T) {
186â†’	t.Helper()
187â†’	if !EntireAvailable() {
188â†’		const msg = "entire binary not available (set E2E_ENTIRE_BIN or install entire)"
189â†’		if os.Getenv("E2E_REQUIRE_LIFECYCLE") == "1" {
190â†’			t.Fatal(msg)
191â†’		}
192â†’		t.Skip("skipping: " + msg)
193â†’	}
194â†’}
195â†’
196â†’// requireKiroCLI fails or skips the test if kiro-cli-chat is not in PATH.
197â†’// When E2E_REQUIRE_LIFECYCLE=1, it fails instead of skipping.
198â†’func requireKiroCLI(t *testing.T) {
199â†’	t.Helper()
200â†’	if _, err := exec.LookPath("kiro-cli-chat"); err != nil {
201â†’		const msg = "kiro-cli-chat not in PATH"
202â†’		if os.Getenv("E2E_REQUIRE_LIFECYCLE") == "1" {
203â†’			t.Fatal(msg)
204â†’		}
205â†’		t.Skip("skipping: " + msg)
206â†’	}
207â†’}
208â†’
209â†’// lifecycleEnv builds the environment variable slice for lifecycle tests.
210â†’// It includes the current PATH so that `entire` and `kiro-cli-chat` can be found.
211â†’func lifecycleEnv(repoRoot, homeDir string) []string {
212â†’	return []string{
213â†’		fmt.Sprintf("ENTIRE_REPO_ROOT=%s", repoRoot),
214â†’		fmt.Sprintf("HOME=%s", homeDir),
215â†’		fmt.Sprintf("PATH=%s", os.Getenv("PATH")),
216â†’		"LANG=en_US.UTF-8",
217â†’	}
218â†’}
219â†’

